import { type PropsWithChildren } from 'react';

import { Zoom } from './Zoom.js';
import { ZoomToFit } from './ZoomToFit.js';
import type { ChartInteractionsProps } from '../types/toolbar.js';

/**
 * ChartInteractions slot component.
 */
const ChartInteractionsRoot = (
  props: PropsWithChildren<ChartInteractionsProps>,
) => null;

ChartInteractionsRoot['displayName'] = 'ChartInteractions';

/**
 * ChartInteractions interactions slot component. @deprecated ChartInteractions is deprecated, please use `<[MapView].Zoom/>` instead.
 * @public
 */

export const ChartInteractions = Object.assign(ChartInteractionsRoot, {
  Zoom,
  ZoomToFit,
});
